import React from 'react';

function DressCode() {
  return (
    <div className="w-full h-full bg-white flex flex-col items-center justify-center gap-5 py-28">
      <p className="text-primary text-2xl">
        Nuestro código de vestimenta es formal elegante
      </p>
      <p className="text-4xl text-[#656c64]">
        Vení con tu mejor outfit y disfruta de la celebración con nosotros!!
      </p>
    </div>
  );
}

export default DressCode;
